fixed_code:
use std::collections::HashMap;

#[derive(Debug)]
struct MyStruct {
    map: HashMap<String, i32>,
}

impl MyStruct {
    fn get_value(&self, key: &str) -> Option<&i32> {
        self.map.get(key)
    }
}

fn main() {
    let s = MyStruct { map: HashMap::new() };
    match s.get_value("foo") {
        Some(value) => println!("{}", value),
        None => println!("Key not found"),
    }
}

