use std::collections::HashMap;

#[derive(Debug)]
struct MyStruct {
    map: HashMap<String, i32>,
}

impl MyStruct {
    fn get_value(&self, key: &str) -> Option<&i32> {
        self.map.get(key)
    }
}

fn main() {
    let s = MyStruct { map: HashMap::new() };
    for _ in 0..5 {
        if let Some(value) = s.get_value("key") {
